'use client'

import { motion } from 'framer-motion'
import { useState } from 'react'
import { useRouter } from 'next/navigation'
import type { CSSProperties } from 'react'
import styles from './SplashScreen.module.css'

const TITLE_CHARS = 'IRON\u00A0THRONE'.split('')

const HOUSES = [
  'House Stark',
  'House Lannister',
  'House Targaryen',
  'House Tyrell',
]

const HERO_DUST = [
  { left: '8%', top: '20%', delay: 0.5, duration: 7.8, scale: 0.8 },
  { left: '18%', top: '68%', delay: 1.2, duration: 9.2, scale: 1.1 },
  { left: '29%', top: '34%', delay: 0.9, duration: 8.6, scale: 0.7 },
  { left: '41%', top: '58%', delay: 1.8, duration: 10.4, scale: 1.2 },
  { left: '54%', top: '24%', delay: 0.3, duration: 8.1, scale: 0.9 },
  { left: '63%', top: '72%', delay: 1.5, duration: 9.8, scale: 1.05 },
  { left: '76%', top: '40%', delay: 0.7, duration: 8.9, scale: 0.85 },
  { left: '87%', top: '18%', delay: 1.9, duration: 10.8, scale: 1.15 },
]

const HERO_IMAGE = '/images/ui/ironthrone.jpg'
const REVEAL_IMAGE = '/images/ui/got-main-splash.png'

type RevealPiece = {
  id: string
  clipPath: string
  start: { x: number; y: number; rotate: number; scale: number }
}

const REVEAL_COLS = 4
const REVEAL_ROWS = 3

const REVEAL_PIECES: RevealPiece[] = Array.from(
  { length: REVEAL_COLS * REVEAL_ROWS },
  (_, idx) => {
    const col = idx % REVEAL_COLS
    const row = Math.floor(idx / REVEAL_COLS)

    const left = (col / REVEAL_COLS) * 100
    const right = ((col + 1) / REVEAL_COLS) * 100
    const top = (row / REVEAL_ROWS) * 100
    const bottom = ((row + 1) / REVEAL_ROWS) * 100

    const fromLeft = col < REVEAL_COLS / 2
    const horizontalDistance = fromLeft
      ? -(740 + col * 70)
      : 740 + (REVEAL_COLS - col) * 70
    const verticalOffset = (row - 1) * 32

    return {
      id: `piece-${row}-${col}`,
      clipPath: `polygon(${left}% ${top}%, ${right}% ${top}%, ${right}% ${bottom}%, ${left}% ${bottom}%)`,
      start: {
        x: horizontalDistance,
        y: verticalOffset,
        rotate: fromLeft ? -10 + row * 2 : 10 - row * 2,
        scale: 1.1,
      },
    }
  }
)

export default function SplashScreen() {
  const [exiting, setExiting] = useState(false)
  const router = useRouter()

  const handleEnter = () => {
    setExiting(true)
    setTimeout(() => router.push('/simulation'), 900)
  }

  return (
    <div className={styles.root}>
      {/* Fire glow background */}
      <div className={styles.bg} />

      {/* ── Opening cinematic hero (pseudo-3D) ── */}
      <motion.div
        className={styles.heroStage}
        initial={{ opacity: 0 }}
        animate={{ opacity: [0, 1, 1, 0] }}
        transition={{ duration: 6.2, times: [0, 0.14, 0.8, 1] }}
      >
        <motion.div
          className={styles.heroCard}
          style={{ transformPerspective: 1400 }}
          initial={{ scale: 1.2, rotateX: 9, rotateY: -12, y: 46 }}
          animate={{
            scale: [1.2, 1.04, 1.08],
            rotateX: [9, 2, -2.2],
            rotateY: [-12, 4, -3],
            y: [46, 2, -14],
          }}
          transition={{
            duration: 7.2,
            ease: [0.2, 0.9, 0.2, 1],
            times: [0, 0.66, 1],
          }}
        >
          <div
            className={styles.heroImage}
            style={{ backgroundImage: `url(${HERO_IMAGE})` }}
          />
          <div className={styles.heroDustLayer}>
            {HERO_DUST.map((particle, index) => (
              <motion.span
                key={`${particle.left}-${particle.top}-${index}`}
                className={styles.heroDust}
                style={{
                  left: particle.left,
                  top: particle.top,
                  scale: `${particle.scale}`,
                }}
                initial={{ opacity: 0, x: -10, y: 18 }}
                animate={{
                  opacity: [0, 0.22, 0.12, 0],
                  x: [-10, 34, 76],
                  y: [18, -8, -34],
                }}
                transition={{
                  duration: particle.duration,
                  delay: particle.delay,
                  repeat: Number.POSITIVE_INFINITY,
                  ease: 'easeInOut',
                }}
              />
            ))}
          </div>
          <motion.div
            className={styles.heroShine}
            initial={{ opacity: 0, x: '-64%' }}
            animate={{ opacity: [0, 0.44, 0], x: ['-64%', '22%', '88%'] }}
            transition={{ duration: 1.7, delay: 1.15, times: [0, 0.45, 1] }}
          />
          <div className={styles.heroVignette} />
        </motion.div>

        <motion.div
          className={styles.heroAtmosphere}
          initial={{ opacity: 0 }}
          animate={{ opacity: [0, 0.8, 0.35] }}
          transition={{ duration: 2.3, delay: 0.9, times: [0, 0.55, 1] }}
        />
      </motion.div>

      {/* ── Intro text / UI overlay ── */}
      <motion.div
        className={styles.overlay}
        initial={{ opacity: 0 }}
        animate={{ opacity: [0, 1, 1, 0] }}
        transition={{
          duration: 6.2,
          times: [0, 0.16, 0.84, 1],
        }}
      >
        {/* Top ornament */}
        <motion.div
          className={styles.ornament}
          initial={{ opacity: 0, scaleX: 0 }}
          animate={{ opacity: 0.65, scaleX: 1 }}
          transition={{ duration: 1, delay: 1.4 }}
        >
          ✦ ── ── ── ── ── ── ── ── ── ── ✦
        </motion.div>

        {/* Letter-by-letter title reveal */}
        <h1 className={styles.title}>
          {TITLE_CHARS.map((char, i) => (
            <motion.span
              key={i}
              initial={{ opacity: 0, y: -45, filter: 'blur(10px)' }}
              animate={{ opacity: 1, y: 0, filter: 'blur(0px)' }}
              transition={{
                duration: 0.55,
                delay: 1.75 + i * 0.075,
                ease: 'easeOut',
              }}
            >
              {char}
            </motion.span>
          ))}
        </h1>

        {/* Subtitle — letter-spacing animates in */}
        <motion.p
          className={styles.subtitle}
          initial={{ opacity: 0, letterSpacing: '0.15em' }}
          animate={{ opacity: 1, letterSpacing: '0.5em' }}
          transition={{ duration: 1.4, delay: 3.0 }}
        >
          Chaos of Crowns
        </motion.p>

        {/* Gold divider */}
        <motion.div
          className={styles.divider}
          initial={{ scaleX: 0 }}
          animate={{ scaleX: 1 }}
          transition={{ duration: 0.9, delay: 3.5 }}
        />

        {/* House names — staggered */}
        <motion.div
          className={styles.housesRow}
          initial="hidden"
          animate="visible"
          variants={{
            visible: {
              transition: { staggerChildren: 0.14, delayChildren: 3.7 },
            },
            hidden: {},
          }}
        >
          {HOUSES.map((house, i) => (
            <motion.span
              key={house}
              className={styles.houseName}
              variants={{
                hidden: { opacity: 0, y: 10 },
                visible: { opacity: 1, y: 0, transition: { duration: 0.4 } },
              }}
            >
              {house}
              {i < HOUSES.length - 1 && (
                <span className={styles.dot}>◆</span>
              )}
            </motion.span>
          ))}
        </motion.div>

        {/* Bottom ornament */}
        <motion.div
          className={styles.ornament}
          initial={{ opacity: 0, scaleX: 0 }}
          animate={{ opacity: 0.65, scaleX: 1 }}
          transition={{ duration: 1, delay: 4.8 }}
        >
          ✦ ── ── ── ── ── ── ── ── ── ── ✦
        </motion.div>
      </motion.div>

      {/* Final cinematic reveal: image pieces fly in and fuse */}
      <motion.div
        className={styles.finalReveal}
        initial={{ opacity: 0 }}
        animate={{ opacity: [0, 0, 1, 1] }}
        transition={{ duration: 8.8, times: [0, 0.56, 0.72, 1] }}
      >
        <motion.div
          className={styles.revealFrame}
          initial={{ scale: 1.06, filter: 'blur(8px)' }}
          animate={{ scale: 1, filter: 'blur(0px)' }}
          transition={{ duration: 1.2, delay: 6.1, ease: [0.16, 1, 0.3, 1] }}
        >
          {REVEAL_PIECES.map((piece, index) => {
            const pieceStyle: CSSProperties = {
              clipPath: piece.clipPath,
              backgroundImage: `url(${REVEAL_IMAGE})`,
            }

            return (
              <motion.div
                key={piece.id}
                className={styles.revealPiece}
                style={pieceStyle}
                initial={{
                  opacity: 0,
                  x: piece.start.x,
                  y: piece.start.y,
                  rotate: piece.start.rotate,
                  scale: piece.start.scale,
                  filter: 'blur(8px)',
                }}
                animate={{
                  opacity: 1,
                  x: 0,
                  y: 0,
                  rotate: 0,
                  scale: 1,
                  filter: 'blur(0px)',
                }}
                transition={{
                  duration: 1.05,
                  delay: 6.2 + index * 0.13,
                  ease: [0.22, 1, 0.36, 1],
                }}
              />
            )
          })}

          <motion.div
            className={styles.revealGlow}
            initial={{ opacity: 0 }}
            animate={{ opacity: [0, 0.9, 0.35] }}
            transition={{ duration: 1.1, delay: 7.15, times: [0, 0.45, 1] }}
          />
        </motion.div>

        <motion.button
          className={styles.enterBtn}
          initial={{ opacity: 0, y: 18 }}
          animate={{ opacity: 1, y: 0 }}
          transition={{ duration: 0.85, delay: 7.55 }}
          whileHover={{ scale: 1.04 }}
          whileTap={{ scale: 0.96 }}
          onClick={handleEnter}
        >
          Enter the Realm
        </motion.button>
      </motion.div>

      {/* Black fade-out when entering realm */}
      {exiting && (
        <motion.div
          className={styles.exitOverlay}
          initial={{ opacity: 0 }}
          animate={{ opacity: 1 }}
          transition={{ duration: 0.85 }}
        />
      )}
    </div>
  )
}
